// TypeScript interfaces for the Renewable Energy Executive Dashboard

export interface MarketMetric {
  readonly label: string;
  readonly value: string;
  readonly unit?: string;
  readonly change?: number;
  readonly changeLabel?: string;
  readonly trend?: "up" | "down" | "neutral";
}

export interface MarketTrendDataPoint {
  year: number;
  value: number;
  label?: string;
}

export interface RegionalAdoptionData {
  state: string;
  adoptionRate: number;
  leedProjects?: number;
  region: "Northeast" | "Southeast" | "Midwest" | "West" | "Southwest";
}

export interface AdoptionByFirmSize {
  firmSize: string;
  revenueRange: string;
  esgPrograms: number;
  leedExperience: number;
  electricEquipment: number;
}

export interface TechnologyProfile {
  id: string;
  name: string;
  category: "Electric Equipment" | "On-site Solar" | "Green Building Systems";
  feasibilityScore: number;
  tcoSavingsMin: number;
  tcoSavingsMax: number;
  tcoSavingsPeriod?: string;
  implementationTimelineMin: number;
  implementationTimelineMax: number;
  paybackPeriodMin: number;
  paybackPeriodMax: number;
  description: string;
  keyBenefits: string[];
  challenges: string[];
  marketSize?: string;
  cagr?: number;
}

export interface FinancialScenario {
  label: "Conservative" | "Moderate" | "Aggressive";
  investmentAmount: number;
  incentiveUtilization: number;
  contractPremium: number;
  roi: number;
  paybackPeriod: number;
  npv?: number;
  annualSavings?: number;
}

export interface CaseStudy {
  id: string;
  company: string;
  firmSize: "Small" | "Mid-Size" | "Mid-Large" | "Large";
  technologies: string[];
  annualRevenue: string;
  keyMetrics: {
    label: string;
    value: string;
  }[];
  highlights: string[];
  enrRanking?: string;
}

export interface RegulatoryIncentive {
  id: string;
  name: string;
  type: "Federal Tax Credit" | "Federal Deduction" | "Federal Mandate" | "State Mandate" | "State Incentive";
  value: string;
  valueNumeric?: number;
  eligibility: string;
  description: string;
  effectiveDate?: string;
  expirationDate?: string;
  financialImpact: string;
}

export interface DashboardSummary {
  marketMetrics: MarketMetric[];
  strategicRecommendations: string[];
  lastUpdated: string;
}

export interface ROICalculatorInputs {
  investmentAmount: number;
  incentiveUtilization: number;
  contractPremium: number;
  projectDuration: number;
}

export interface ROICalculatorResult {
  paybackPeriod: number;
  roi: number;
  netSavings: number;
  annualSavings: number;
  incentiveSavings: number;
}

export interface MarketData {
  trends: MarketTrendDataPoint[];
  regionalAdoption: RegionalAdoptionData[];
  adoptionByFirmSize: AdoptionByFirmSize[];
  projections: MarketTrendDataPoint[];
}

export interface TechnologyData {
  technologies: TechnologyProfile[];
}

export interface FinancialData {
  scenarios: FinancialScenario[];
  defaultInputs: ROICalculatorInputs;
}

export interface BenchmarkData {
  caseStudies: CaseStudy[];
}

export interface RegulatoryData {
  incentives: RegulatoryIncentive[];
}

// API client with backend fetch and mock data fallback
import {
  MARKET_DATA,
  TECHNOLOGY_DATA,
  FINANCIAL_DATA,
  BENCHMARK_DATA,
  REGULATORY_DATA,
  DASHBOARD_SUMMARY,
} from "./data";
import type {
  MarketData,
  TechnologyData,
  FinancialData,
  BenchmarkData,
  RegulatoryData,
  DashboardSummary,
} from "./types";

const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL ?? "http://localhost:8000/api";
const FETCH_TIMEOUT_MS = 3000;

async function fetchWithTimeout<T>(url: string): Promise<T> {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS);

  try {
    const res = await fetch(url, {
      signal: controller.signal,
      headers: { "Content-Type": "application/json" },
      cache: "no-store",
    });
    clearTimeout(timeoutId);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return (await res.json()) as T;
  } catch {
    clearTimeout(timeoutId);
    throw new Error("Backend unavailable");
  }
}

export async function getMarketData(): Promise<MarketData> {
  try {
    return await fetchWithTimeout<MarketData>(`${API_BASE_URL}/market-trends`);
  } catch {
    return MARKET_DATA;
  }
}

export async function getTechnologyData(): Promise<TechnologyData> {
  try {
    return await fetchWithTimeout<TechnologyData>(`${API_BASE_URL}/technologies`);
  } catch {
    return TECHNOLOGY_DATA;
  }
}

export async function getFinancialData(): Promise<FinancialData> {
  try {
    return await fetchWithTimeout<FinancialData>(`${API_BASE_URL}/financial`);
  } catch {
    return FINANCIAL_DATA;
  }
}

export async function getBenchmarkData(): Promise<BenchmarkData> {
  try {
    return await fetchWithTimeout<BenchmarkData>(`${API_BASE_URL}/benchmarking`);
  } catch {
    return BENCHMARK_DATA;
  }
}

export async function getRegulatoryData(): Promise<RegulatoryData> {
  try {
    return await fetchWithTimeout<RegulatoryData>(`${API_BASE_URL}/regulatory`);
  } catch {
    return REGULATORY_DATA;
  }
}

export async function getDashboardSummary(): Promise<DashboardSummary> {
  try {
    return await fetchWithTimeout<DashboardSummary>(`${API_BASE_URL}/summary`);
  } catch {
    return DASHBOARD_SUMMARY;
  }
}

"use client";

import type { MarketMetric } from "@/lib/types";

interface MetricCardProps {
  metric: MarketMetric;
  className?: string;
}

export function MetricCard({ metric, className = "" }: MetricCardProps) {
  const trendIcon =
    metric.trend === "up" ? "↑" : metric.trend === "down" ? "↓" : "→";
  const trendColor =
    metric.trend === "up"
      ? "text-emerald-400"
      : metric.trend === "down"
        ? "text-amber-400"
        : "text-slate-400";

  return (
    <div
      className={`bg-slate-800 border border-slate-700 rounded-xl p-5 hover:border-emerald-600 transition-colors ${className}`}
    >
      <p className="text-xs font-medium text-slate-400 uppercase tracking-wider mb-2">
        {metric.label}
      </p>
      <p className="text-2xl font-bold text-white mb-1">{metric.value}</p>
      {metric.unit && (
        <p className="text-xs text-slate-500 mb-2">{metric.unit}</p>
      )}
      {metric.change !== undefined && (
        <div className={`flex items-center gap-1 text-xs font-medium ${trendColor}`}>
          <span>{trendIcon}</span>
          <span>
            {Math.abs(metric.change)}%{" "}
            {metric.changeLabel ?? "change"}
          </span>
        </div>
      )}
    </div>
  );
}

"use client";

import type { ReactNode } from "react";

interface ChartCardProps {
  title: string;
  subtitle?: string;
  children: ReactNode;
  className?: string;
  headerAction?: ReactNode;
}

export function ChartCard({
  title,
  subtitle,
  children,
  className = "",
  headerAction,
}: ChartCardProps) {
  return (
    <div
      className={`bg-slate-800 border border-slate-700 rounded-xl p-6 ${className}`}
    >
      <div className="flex items-start justify-between mb-4">
        <div>
          <h3 className="text-sm font-semibold text-white">{title}</h3>
          {subtitle && (
            <p className="text-xs text-slate-400 mt-0.5">{subtitle}</p>
          )}
        </div>
        {headerAction && <div>{headerAction}</div>}
      </div>
      {children}
    </div>
  );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";

interface NavItem {
  href: string;
  label: string;
  icon: string;
  description: string;
}

const NAV_ITEMS: NavItem[] = [
  {
    href: "/",
    label: "Executive Summary",
    icon: "◈",
    description: "Key metrics & strategy",
  },
  {
    href: "/market-trends",
    label: "Market Trends",
    icon: "↗",
    description: "Adoption & growth data",
  },
  {
    href: "/technology",
    label: "Technology Comparison",
    icon: "⚙",
    description: "Solar, electric, green systems",
  },
  {
    href: "/financial",
    label: "Financial Analysis",
    icon: "$",
    description: "ROI calculator & scenarios",
  },
  {
    href: "/benchmarking",
    label: "Competitive Benchmarking",
    icon: "▣",
    description: "Peer case studies",
  },
  {
    href: "/regulatory",
    label: "Regulatory Incentives",
    icon: "✦",
    description: "Policies & tax credits",
  },
];

export function Sidebar() {
  const pathname = usePathname();

  return (
    <aside
      className="w-64 min-h-screen bg-slate-900 border-r border-slate-800 flex flex-col"
      aria-label="Main navigation"
    >
      {/* Logo / Brand */}
      <div className="p-6 border-b border-slate-800">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-emerald-600 rounded-lg flex items-center justify-center">
            <span className="text-white text-sm font-bold">RE</span>
          </div>
          <div>
            <p className="text-white text-sm font-semibold leading-tight">
              RenewEnergy
            </p>
            <p className="text-slate-500 text-xs">Executive Dashboard</p>
          </div>
        </div>
      </div>

      {/* Navigation */}
      <nav className="flex-1 p-4" aria-label="Dashboard sections">
        <ul className="space-y-1" role="list">
          {NAV_ITEMS.map((item) => {
            const isActive =
              item.href === "/"
                ? pathname === "/"
                : pathname.startsWith(item.href);

            return (
              <li key={item.href}>
                <Link
                  href={item.href}
                  className={`group flex items-start gap-3 px-3 py-2.5 rounded-lg transition-all ${
